public void insert()
{
    next insert();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        str descriptiveKeyCollection = strFmt("ChartOfAccounts='%1', MainAccountId='%2'",
            LedgerChartOfAccounts::find(this.LedgerChartOfAccounts).Name,
            this.MainAccountId);

        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();
        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("MainAccounts");
        contract.parmoperationType("Insert");
        //  contract.parmDataAreaId(this.da);

        ETGDMSRevereIntegrationEventClass eventClass = ETGDMSRevereIntegrationEventClass::newFromContract(contract);
        eventClass.send();
    }

}

public void update()
{
    MainAccount mainAccountOrig = this.orig();
    MainAccountNum oldMainAccountId = mainAccountOrig.MainAccountId;

    next update();

    if (BusinessEventsConfigurationReader::isBusinessEventEnabled(classStr(ETGDMSRevereIntegrationEventClass)))
    {
        str oldAccountValue = "";

        if (this.MainAccountId != oldMainAccountId)
        {
            oldAccountValue = oldMainAccountId;
        }

        str descriptiveKeyCollection = strFmt("ChartOfAccounts='%1', MainAccountId='%2', MainAccountOld='%3'",
            LedgerChartOfAccounts::find(this.LedgerChartOfAccounts).Name,
            this.MainAccountId,oldAccountValue);

        ETGDMSRevereIntegrationContract contract = new ETGDMSRevereIntegrationContract();
        contract.parmPrimaryKeyCollection(descriptiveKeyCollection);
        contract.parmPrimaryCollectionName("MainAccounts");
        contract.parmoperationType("Update");

        ETGDMSRevereIntegrationEventClass eventClass = ETGDMSRevereIntegrationEventClass::newFromContract(contract);
        eventClass.send();

    }

}
